/* ------------------------------
 * GROUP 5 - updateGtmTom3phInvDuty: initialization / enable guard
 * ------------------------------ */
void test_TC_G5_001_update_called_once_when_gtm_initially_disabled_after_init(void)
{
    /* Arrange */
